def gen(rng, size):
    digit_count = rng.randint(2, max(2, min(size, 60)))
    digits = [str(rng.randint(0, 9)) for _ in range(digit_count)]
    out = []
    for i, d in enumerate(digits):
        out.append(d)
        if i != len(digits) - 1 and rng.random() < 0.3:
            out.append(rng.choice([' ', '-']))
    return [''.join(out)]

