class Solution:
    def reformatNumber(self, number):
        digits = [c for c in number if c.isdigit()]
        blocks = []
        i = 0
        remaining = len(digits)
        while remaining > 4:
            blocks.append(''.join(digits[i:i + 3]))
            i += 3
            remaining -= 3
        if remaining == 4:
            blocks.append(''.join(digits[i:i + 2]))
            blocks.append(''.join(digits[i + 2:i + 4]))
        elif remaining in (2, 3):
            blocks.append(''.join(digits[i:i + remaining]))
        return '-'.join(blocks)

