class Solution:
    def reformatNumber(self, number: str) -> str:
        digits = ''.join(c for c in number if c.isdigit())
        blocks = []
        n = len(digits)
        i = 0
        while n - i > 4:
            blocks.append(digits[i:i + 3])
            i += 3
        left = n - i
        if left == 4:
            blocks.append(digits[i:i + 2])
            blocks.append(digits[i + 2:i + 4])
        else:
            blocks.append(digits[i:])
        return '-'.join(blocks)

